insert into public.temas (slug, nombre, descripcion, orden)
values ('introduccion-ia', 'Introducción a los sistemas inteligentes y la IA', 'Recorrido por los fundamentos, la historia y la evolución de la inteligencia artificial: qué es un sistema inteligente, la diferencia entre IA débil y fuerte, y los enfoques que buscan que las máquinas piensen o actúen de forma racional o como humanos. Introduce el Test de Turing, los niveles evolutivos de la IA y la noción de agente inteligente.', 1)
on conflict (slug) do update set
  nombre = excluded.nombre, descripcion = excluded.descripcion, orden = excluded.orden;

insert into public.temas (slug, nombre, descripcion, orden)
values ('resolucion-problemas-busqueda', 'Resolución de problemas y búsqueda', 'Técnicas que permiten a un agente formular un problema en términos de estados y acciones y explorar sistemáticamente el espacio de estados para hallar una secuencia que lleve al objetivo. Incluye árboles de búsqueda, búsqueda ciega y heurística (A*) y algoritmos adversariales como minimax y poda alfa-beta en juegos de dos jugadores.', 2)
on conflict (slug) do update set
  nombre = excluded.nombre, descripcion = excluded.descripcion, orden = excluded.orden;

insert into public.temas (slug, nombre, descripcion, orden)
values ('representacion-conocimiento', 'Representación del conocimiento y razonamiento', 'Estudia cómo codificar información sobre el mundo en estructuras que una computadora pueda usar para razonar. Abarca la jerarquía dato-información-conocimiento, la lógica y los sistemas de reglas, las ontologías y la distinción entre conocimiento declarativo y procedimental, base de los sistemas expertos y la web semántica.', 3)
on conflict (slug) do update set
  nombre = excluded.nombre, descripcion = excluded.descripcion, orden = excluded.orden;

insert into public.temas (slug, nombre, descripcion, orden)
values ('aprendizaje-automatico', 'Aprendizaje automático', 'Conjunto de técnicas mediante las cuales un sistema mejora su desempeño a partir de los datos, sin ser programado explícitamente para cada tarea. Comprende el aprendizaje supervisado, no supervisado y por refuerzo, con algoritmos como la regresión, los árboles de decisión, k-medias o Q-learning.', 4)
on conflict (slug) do update set
  nombre = excluded.nombre, descripcion = excluded.descripcion, orden = excluded.orden;

insert into public.temas (slug, nombre, descripcion, orden)
values ('redes-neuronales-deep-learning', 'Redes neuronales y aprendizaje profundo', 'Subcampo del aprendizaje automático inspirado en el sistema nervioso, basado en neuronas artificiales interconectadas mediante pesos y funciones de activación. Las redes profundas, con múltiples capas, permiten abstraer representaciones de alto nivel para resolver problemas complejos de visión, lenguaje y voz.', 5)
on conflict (slug) do update set
  nombre = excluded.nombre, descripcion = excluded.descripcion, orden = excluded.orden;

insert into public.temas (slug, nombre, descripcion, orden)
values ('reconocimiento-patrones-pln', 'Reconocimiento de patrones y procesamiento del lenguaje natural', 'Aplica el aprendizaje automático y profundo para percibir y clasificar señales del mundo real: imágenes, voz y texto. Cubre el ciclo de reconocimiento (sensado, segmentación, extracción de características y clasificación), las redes convolucionales, el reconocimiento del habla y el procesamiento del lenguaje natural.', 6)
on conflict (slug) do update set
  nombre = excluded.nombre, descripcion = excluded.descripcion, orden = excluded.orden;

