insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'chatgpt', (select id from public.temas where slug = 'introduccion-ia'),
  'ChatGPT', 'Generar respuestas conversacionales en lenguaje natural a partir de las indicaciones del usuario, asistiendo en tareas de redacción, consulta, programación y aprendizaje.', 'ChatGPT es un asistente conversacional basado en inteligencia artificial desarrollado por OpenAI, construido sobre modelos de lenguaje de gran escala de la familia GPT. Permite mantener diálogos en lenguaje natural para responder preguntas, redactar y resumir textos, traducir, escribir y depurar código, entre otras tareas. Se accede a través de una interfaz web y dispone de versiones gratuitas y de pago.', 'https://chatgpt.com/', 'Propietaria (gratuita con límites)', 2022, 'OpenAI', 'https://www.youtube.com/watch?v=3u1k7Jyn434', 'https://upload.wikimedia.org/wikipedia/commons/e/ef/ChatGPT-Logo.svg'
on conflict (slug) do update set
