  autor_referencia = excluded.autor_referencia, video_url = excluded.video_url, imagen_url = excluded.imagen_url;

insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'teachable-machine', (select id from public.temas where slug = 'introduccion-ia'),
  'Google Teachable Machine', 'Permite crear modelos de aprendizaje automático (para reconocer imágenes, sonidos y posturas) de forma rápida y sin necesidad de programar.', 'Google Teachable Machine es una herramienta web gratuita desarrollada por Google Creative Lab que facilita la creación de modelos de aprendizaje automático sin requerir conocimientos de programación. Funciona en el navegador mediante TensorFlow.js y permite entrenar clasificadores de imágenes, sonidos y poses a partir de la cámara web, el micrófono o archivos cargados por el usuario. Los modelos resultantes se pueden exportar para integrarlos en sitios web y aplicaciones.', 'https://teachablemachine.withgoogle.com/', 'Apache 2.0', 2017, 'Google Creative Lab', 'https://www.youtube.com/watch?v=wU4ARWLp4sU', null
on conflict (slug) do update set
  tema_id = excluded.tema_id,
  nombre = excluded.nombre, objetivo = excluded.objetivo, descripcion_corta = excluded.descripcion_corta,
