insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'gymnasium', (select id from public.temas where slug = 'resolucion-problemas-busqueda'),
  'Gymnasium (ex OpenAI Gym)', 'Proporciona una API estandarizada y una colección de entornos de referencia para desarrollar, comparar y evaluar algoritmos de aprendizaje por refuerzo.', 'Gymnasium es una biblioteca de código abierto que define una interfaz estándar para crear e interactuar con entornos de aprendizaje por refuerzo (reinforcement learning). Es el sucesor mantenido de OpenAI Gym, gestionado por la Farama Foundation, e incluye una amplia variedad de entornos de referencia como CartPole, Atari y simulaciones robóticas. Permite que los agentes aprendan mediante prueba y error a través de funciones bien definidas como reset() y step().', 'https://gymnasium.farama.org/', 'MIT', 2022, 'Farama Foundation (originalmente OpenAI)', 'https://www.youtube.com/watch?v=Y_UqXz6aqfY', null
on conflict (slug) do update set
  tema_id = excluded.tema_id,
  nombre = excluded.nombre, objetivo = excluded.objetivo, descripcion_corta = excluded.descripcion_corta,
