  autor_referencia = excluded.autor_referencia, video_url = excluded.video_url, imagen_url = excluded.imagen_url;

insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'stockfish', (select id from public.temas where slug = 'resolucion-problemas-busqueda'),
  'Stockfish', 'Analizar partidas de ajedrez y calcular las mejores jugadas mediante un motor de búsqueda y evaluación de posiciones de código abierto.', 'Stockfish es uno de los motores de ajedrez de código abierto más potentes del mundo, capaz de evaluar posiciones y proponer las mejores jugadas con una fuerza muy superior a la de los grandes maestros humanos. Escrito en C++ y compatible con el protocolo UCI, se integra en numerosas plataformas y programas de ajedrez para analizar partidas y entrenar jugadores de todos los niveles. Desde 2020 incorpora redes neuronales (NNUE) que mejoran de forma notable la precisión de su evaluación.', 'https://stockfishchess.org/', 'GPL v3', 2008, 'Tord Romstad, Marco Costalba, Joona Kiiski, Gary Linscott y la comunidad de Stockfish', 'https://www.youtube.com/watch?v=ZSf8Sp76qp8', 'https://upload.wikimedia.org/wikipedia/commons/3/3a/NewLogoSF.png'
on conflict (slug) do update set
  tema_id = excluded.tema_id,
  nombre = excluded.nombre, objetivo = excluded.objetivo, descripcion_corta = excluded.descripcion_corta,
  url_acceso = excluded.url_acceso, licencia = excluded.licencia, anio_lanzamiento = excluded.anio_lanzamiento,
  autor_referencia = excluded.autor_referencia, video_url = excluded.video_url, imagen_url = excluded.imagen_url;

insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'or-tools', (select id from public.temas where slug = 'resolucion-problemas-busqueda'),
  'Google OR-Tools', 'Resolver problemas de optimización combinatoria, como enrutamiento, planificación, asignación y programación lineal y de restricciones, encontrando la mejor solución entre un gran conjunto de posibilidades.', 'Google OR-Tools es una suite de software libre y de código abierto desarrollada por Google para la investigación de operaciones y la optimización combinatoria. Incluye solucionadores para programación lineal (LP), programación de enteros mixtos (MIP), programación de restricciones (CP) y enrutamiento de vehículos (VRP), entre otros. Escrita en C++, permite modelar problemas también desde Python, Java y C#, y se aplica en logística, planificación de horarios y asignación de recursos.', 'https://developers.google.com/optimization?hl=es-419', 'Apache 2.0', 2010, 'Google (autor original Laurent Perron)', 'https://www.youtube.com/watch?v=XPiDrFl5S84', null
on conflict (slug) do update set
  tema_id = excluded.tema_id,
  nombre = excluded.nombre, objetivo = excluded.objetivo, descripcion_corta = excluded.descripcion_corta,
