insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'protege', (select id from public.temas where slug = 'representacion-conocimiento'),
  'Protégé', 'Permite crear, editar y gestionar ontologías y bases de conocimiento mediante lenguajes estándar como OWL y RDF.', 'Protégé es un editor de ontologías gratuito y de código abierto desarrollado en la Universidad de Stanford. Permite construir representaciones formales del conocimiento de un dominio utilizando estándares de la Web Semántica como OWL y RDF, y se integra con razonadores de lógica descriptiva. Está disponible como aplicación de escritorio (Protégé Desktop) y en una versión colaborativa basada en navegador (WebProtégé).', 'https://protege.stanford.edu/', 'BSD 2-Clause', 1999, 'Universidad de Stanford (Stanford Center for Biomedical Informatics Research)', 'https://www.youtube.com/watch?v=N_uOC8xWWBE', 'https://upload.wikimedia.org/wikipedia/commons/7/72/Prot%C3%A9g%C3%A9_Logo.gif'
on conflict (slug) do update set
