insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'swi-prolog', (select id from public.temas where slug = 'representacion-conocimiento'),
  'SWI-Prolog', 'Proporcionar un entorno completo y de código abierto para programar en el lenguaje lógico Prolog, basado en hechos, reglas y consultas.', 'SWI-Prolog es una de las implementaciones de código abierto más utilizadas del lenguaje de programación lógico Prolog. Incluye un intérprete, un entorno de desarrollo con depurador, bibliotecas extensas y herramientas multiplataforma para Windows, Linux y macOS. Se emplea ampliamente en la enseñanza y en aplicaciones de inteligencia artificial, procesamiento de lenguaje natural, sistemas expertos y web semántica.', 'https://www.swi-prolog.org/', 'BSD 2-Clause', 1987, 'Jan Wielemaker (Universidad de Ámsterdam) y comunidad de SWI-Prolog', 'https://www.youtube.com/watch?v=WagksXYJXPY', 'https://upload.wikimedia.org/wikipedia/commons/d/d7/Screenshot_of_SWI_prolog_icon.png'
