insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'scikit-learn', (select id from public.temas where slug = 'aprendizaje-automatico'),
  'scikit-learn', 'Proporcionar herramientas eficientes y de código abierto para el análisis de datos y el aprendizaje automático en Python, abarcando clasificación, regresión, agrupamiento y reducción de dimensionalidad.', 'scikit-learn es una biblioteca de código abierto para aprendizaje automático en el lenguaje Python, construida sobre NumPy, SciPy y Matplotlib. Ofrece una interfaz consistente con algoritmos para tareas de clasificación, regresión, agrupamiento, reducción de dimensionalidad, selección de modelos y preprocesamiento de datos. Es ampliamente utilizada en investigación, educación y aplicaciones industriales por su simplicidad y documentación extensa.', 'https://scikit-learn.org/', 'BSD 3-Clause', 2010, 'Proyecto scikit-learn (iniciado por David Cournapeau; comunidad de contribuyentes)', 'https://www.youtube.com/watch?v=qUjIybMkXBs', 'https://upload.wikimedia.org/wikipedia/commons/0/05/Scikit_learn_logo_small.svg'
