insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'weka', (select id from public.temas where slug = 'aprendizaje-automatico'),
  'Weka', 'Reúne algoritmos de aprendizaje automático y herramientas de minería de datos para preparar datos, clasificar, regresionar, agrupar, encontrar reglas de asociación y visualizar resultados.', 'Weka (Waikato Environment for Knowledge Analysis) es una colección de software de aprendizaje automático y minería de datos desarrollada en la Universidad de Waikato, Nueva Zelanda. Ofrece una interfaz gráfica (Explorer, Experimenter, KnowledgeFlow) y una línea de comandos para aplicar técnicas de clasificación, regresión, agrupamiento, selección de atributos y visualización sobre conjuntos de datos. Es uno de los entornos educativos de minería de datos más utilizados.', 'https://ml.cms.waikato.ac.nz/weka', 'GNU GPL', 1993, 'Machine Learning Group, Universidad de Waikato (Nueva Zelanda)', 'https://www.youtube.com/watch?v=N6itjmU3qeA', 'https://upload.wikimedia.org/wikipedia/commons/0/07/Weka_%28software%29_logo.png'
on conflict (slug) do update set
