  autor_referencia = excluded.autor_referencia, video_url = excluded.video_url, imagen_url = excluded.imagen_url;

insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'orange', (select id from public.temas where slug = 'aprendizaje-automatico'),
  'Orange Data Mining', 'Permite realizar análisis de datos, minería de datos y aprendizaje automático mediante programación visual, conectando bloques (widgets) en un lienzo sin necesidad de escribir código.', 'Orange Data Mining es una suite de software libre de código abierto para visualización de datos, análisis exploratorio, minería de datos y aprendizaje automático. Su interfaz de programación visual permite construir flujos de trabajo arrastrando y conectando componentes llamados widgets, lo que la hace accesible tanto para principiantes como para usuarios avanzados. Está desarrollada en Python y C++, y sus funciones pueden ampliarse con complementos especializados.', 'https://orangedatamining.com/?lang=es', 'GPL v3', 1996, 'Bioinformatics Laboratory, Universidad de Liubliana (Eslovenia)', 'https://www.youtube.com/watch?v=1inAFE3qftw', null
on conflict (slug) do update set
