insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'tensorflow', (select id from public.temas where slug = 'redes-neuronales-deep-learning'),
  'TensorFlow', 'Construir, entrenar y desplegar modelos de aprendizaje automático y redes neuronales mediante grafos de cálculo numérico.', 'TensorFlow es una biblioteca de código abierto para el aprendizaje automático y el aprendizaje profundo, desarrollada por Google. Permite definir y ejecutar cálculos numéricos sobre grafos de flujo de datos, facilitando la creación y el entrenamiento de redes neuronales. Es escalable a múltiples CPU y GPU y ofrece APIs para Python, JavaScript y otros lenguajes.', 'https://www.tensorflow.org/?hl=es', 'Apache 2.0', 2015, 'Google Brain Team', 'https://www.youtube.com/watch?v=bwvf25qmLWM', 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/TensorFlow_logo.svg/250px-TensorFlow_logo.svg.png'
on conflict (slug) do update set
