insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'pytorch', (select id from public.temas where slug = 'redes-neuronales-deep-learning'),
  'PyTorch', 'Construir, entrenar y desplegar redes neuronales y modelos de aprendizaje profundo mediante cálculo con tensores y diferenciación automática.', 'PyTorch es una biblioteca de código abierto para aprendizaje automático y aprendizaje profundo basada en Python. Ofrece cálculo con tensores acelerado por GPU, grafos de cómputo dinámicos y un sistema de diferenciación automática que facilita la creación y el entrenamiento de redes neuronales. Cuenta con un amplio ecosistema de herramientas y es ampliamente utilizada tanto en investigación como en producción.', 'https://pytorch.org/', 'BSD 3-Clause', 2016, 'Meta AI (actualmente PyTorch Foundation, Linux Foundation)', 'https://www.youtube.com/watch?v=QetoD5LXlEg', 'https://upload.wikimedia.org/wikipedia/commons/c/c6/PyTorch_logo_black.svg'
