insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'opencv', (select id from public.temas where slug = 'reconocimiento-patrones-pln'),
  'OpenCV', 'Procesar imágenes y videos para tareas de visión por computadora, como detección de objetos, reconocimiento facial y análisis de imágenes en tiempo real.', 'OpenCV (Open Source Computer Vision Library) es una biblioteca de código abierto orientada a la visión por computadora y el aprendizaje automático. Ofrece miles de algoritmos para procesar imágenes y videos, detectar y reconocer objetos y rostros, y desarrollar aplicaciones de visión artificial. Es multiplataforma y cuenta con interfaces para lenguajes como C++, Python y Java.', 'https://opencv.org/', 'Apache 2.0', 1999, 'Intel (actualmente OpenCV.org / OpenCV Foundation)', 'https://www.youtube.com/watch?v=Nh1eob7tsr0', 'https://upload.wikimedia.org/wikipedia/commons/d/d2/OpenCV_logo_black.svg'
on conflict (slug) do update set
