insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'whisper', (select id from public.temas where slug = 'reconocimiento-patrones-pln'),
  'Whisper (OpenAI)', 'Transcribir y traducir automáticamente audio hablado a texto en múltiples idiomas mediante un modelo de reconocimiento automático del habla.', 'Whisper es un modelo de reconocimiento automático del habla (ASR) de código abierto desarrollado por OpenAI, entrenado con 680.000 horas de datos multilingües y multitarea. Convierte audio en texto con alta precisión, incluso en entornos ruidosos y con acentos variados, y admite tareas de transcripción, traducción e identificación de idioma. Se distribuye como código y pesos de modelo bajo licencia MIT, lo que permite su uso local y privado.', 'https://github.com/openai/whisper', 'MIT', 2022, 'OpenAI', 'https://www.youtube.com/watch?v=n2x43tA-hzI', 'https://upload.wikimedia.org/wikipedia/commons/6/66/OpenAI_logo_2025_%28symbol%29.svg'
on conflict (slug) do update set
