insert into public.software (slug, tema_id, nombre, objetivo, descripcion_corta, url_acceso, licencia, anio_lanzamiento, autor_referencia, video_url, imagen_url)
select 'hugging-face', (select id from public.temas where slug = 'reconocimiento-patrones-pln'),
  'Hugging Face', 'Plataforma colaborativa de código abierto para compartir, descubrir y desplegar modelos de inteligencia artificial, conjuntos de datos y aplicaciones de aprendizaje automático.', 'Hugging Face es una plataforma y comunidad de código abierto dedicada al aprendizaje automático, frecuentemente descrita como el "GitHub de la inteligencia artificial". A través de su Hub permite alojar y compartir cientos de miles de modelos preentrenados, conjuntos de datos y demostraciones interactivas (Spaces). Además mantiene bibliotecas ampliamente utilizadas, como Transformers, Datasets y Diffusers, que facilitan el desarrollo de aplicaciones de IA.', 'https://huggingface.co/', 'Apache 2.0', 2016, 'Hugging Face, Inc. (Clément Delangue, Julien Chaumond y Thomas Wolf)', 'https://www.youtube.com/watch?v=jG4Ns63tTeo', 'https://upload.wikimedia.org/wikipedia/commons/d/d6/Hf-logo-with-title.svg'
