-- DESTRUCTIVE: removes retired temas (and cascades their progreso_roadmap rows).
-- User-gated. Runs after the software upsert because software.tema_id is RESTRICT.
delete from public.temas where slug <> all(array['introduccion-ia', 'resolucion-problemas-busqueda', 'representacion-conocimiento', 'aprendizaje-automatico', 'redes-neuronales-deep-learning', 'reconocimiento-patrones-pln']);

-- Junction: software_clasificaciones (M2M, one row per tool × category).
